"use client";

import * as React from "react";
import { useMotionValueEvent } from "motion/react";

import { cn } from "@/lib/utils";
import { clamp01, useExperienceViewport, usePrefersReducedMotion } from "@/components/experience/experience-runtime";
import { useElementScrollProgress } from "@/components/experience/use-element-scroll-progress";

export type KnockoutTextProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  /** The knocked-out copy. A visually hidden heading keeps it real text. */
  text: string;
  /** Image revealed only through the transparent letterforms. */
  src: string;
  /** Alternate art direction below 640px. */
  mobileSrc?: string;
  /** Dedicated iPad/tablet art direction between 640px and 1023px. */
  tabletSrc?: string;
  /** Semantic element that carries the copy for assistive tech and SEO. */
  as?: "h1" | "h2" | "h3" | "p";
  /** Pinned travel length in scroll screens. */
  scrollScreens?: number;
  /** How far the transparent letterforms advance past the camera. */
  maxScale?: number;
  mobileMaxScale?: number;
  tabletMaxScale?: number;
  /** Continuous destination push-in while the camera crosses the glyph. */
  imageMaxScale?: number;
  mobileImageMaxScale?: number;
  tabletImageMaxScale?: number;
  /** Fallback camera anchor when no focusIndex is supplied. */
  origin?: string;
  mobileOrigin?: string;
  tabletOrigin?: string;
  /** Character whose transparent face becomes the camera path. */
  focusIndex?: number;
  /** Passage point inside that character's inked shape, from 0 to 1. */
  passageX?: number;
  passageY?: number;
  mobilePassageX?: number;
  mobilePassageY?: number;
  tabletPassageX?: number;
  tabletPassageY?: number;
  /** Opaque stage color surrounding the transparent letterforms. */
  curtainColor?: string;
  /** Fixed chrome (eyebrow, hints) above the stage. */
  overlay?: React.ReactNode;
  textClassName?: string;
  stageClassName?: string;
};

const easeInOut = (t: number) => (t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2);

/**
 * A pinned knockout sequence in four beats driven by one scroll travel: the
 * stage starts dark and the headline rises in as solid type. Once fully
 * visible, those exact letterforms become transparent windows onto the image.
 * The selected central glyph then advances until the camera passes through an
 * inked part of its now-transparent shape — never through an artificial circle
 * or through the glyph's counter. The surrounding dark field stays opaque.
 * Scrolling back replays every beat in reverse. A visually hidden heading
 * keeps the copy real; reduced motion shows the composed knockout frame with
 * no pin.
 */
export function KnockoutText({
  as: Tag = "h1",
  className,
  curtainColor = "#050505",
  focusIndex,
  imageMaxScale = 1.5,
  label,
  maxScale = 210,
  mobileImageMaxScale,
  mobileMaxScale,
  mobileOrigin,
  mobilePassageX,
  mobilePassageY,
  mobileSrc,
  origin = "50% 46%",
  overlay,
  passageX = 0.5,
  passageY = 0.55,
  scrollScreens = 3,
  src,
  stageClassName,
  tabletMaxScale,
  tabletImageMaxScale,
  tabletOrigin,
  tabletPassageX,
  tabletPassageY,
  tabletSrc,
  text,
  textClassName,
  ...props
}: KnockoutTextProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const cutoutGroupRef = React.useRef<SVGGElement>(null);
  const cutoutGlyphRefs = React.useRef<Array<SVGTextElement | null>>([]);
  const solidGroupRef = React.useRef<SVGGElement>(null);
  const measureTextRef = React.useRef<SVGTextElement>(null);
  const solidTextRef = React.useRef<SVGTextElement>(null);
  const curtainRef = React.useRef<SVGRectElement>(null);
  const imageRef = React.useRef<HTMLDivElement>(null);
  const passageShiftRef = React.useRef({ x: 0, y: 0 });
  const maskId = React.useId();
  const reducedMotion = usePrefersReducedMotion();
  const viewport = useExperienceViewport();
  const activeSrc = viewport === "mobile"
    ? mobileSrc ?? tabletSrc ?? src
    : viewport === "tablet"
      ? tabletSrc ?? src
      : src;
  const activeMaxScale = viewport === "mobile"
    ? mobileMaxScale ?? tabletMaxScale ?? Math.min(maxScale, 200)
    : viewport === "tablet"
      ? tabletMaxScale ?? Math.min(maxScale, 210)
      : maxScale;
  const activeImageMaxScale = viewport === "mobile"
    ? mobileImageMaxScale ?? tabletImageMaxScale ?? imageMaxScale
    : viewport === "tablet"
      ? tabletImageMaxScale ?? imageMaxScale
      : imageMaxScale;
  const activeOrigin = viewport === "mobile"
    ? mobileOrigin ?? tabletOrigin ?? origin
    : viewport === "tablet"
      ? tabletOrigin ?? origin
      : origin;
  const activePassageX = viewport === "mobile"
    ? mobilePassageX ?? tabletPassageX ?? passageX
    : viewport === "tablet"
      ? tabletPassageX ?? passageX
      : passageX;
  const activePassageY = viewport === "mobile"
    ? mobilePassageY ?? tabletPassageY ?? passageY
    : viewport === "tablet"
      ? tabletPassageY ?? passageY
      : passageY;
  const progress = useElementScrollProgress(rootRef);

  React.useLayoutEffect(() => {
    const measureText = measureTextRef.current;
    const cutoutGroup = cutoutGroupRef.current;
    const solidGroup = solidGroupRef.current;
    if (!measureText || !cutoutGroup || !solidGroup) return;

    let cancelled = false;
    const svg = measureText.ownerSVGElement;
    const updateOrigin = () => {
      if (cancelled) return;
      const count = measureText.getNumberOfChars();
      if (count < 1) return;
      cutoutGlyphRefs.current.forEach((glyph, glyphIndex) => {
        if (!glyph || glyphIndex >= count) return;
        const start = measureText.getStartPositionOfChar(glyphIndex);
        glyph.setAttribute("x", start.x.toFixed(3));
      });
      if (focusIndex === undefined) {
        passageShiftRef.current = { x: 0, y: 0 };
        cutoutGroup.style.transformOrigin = activeOrigin;
        solidGroup.style.transformOrigin = activeOrigin;
        return;
      }
      const index = Math.min(count - 1, Math.max(0, Math.round(focusIndex)));
      const box = measureText.getExtentOfChar(index);
      const x = box.x + box.width * clamp01(activePassageX);
      const y = box.y + box.height * clamp01(activePassageY);
      const measuredOrigin = `${x.toFixed(3)}px ${y.toFixed(3)}px`;
      passageShiftRef.current = {
        x: (svg?.clientWidth ?? 0) * 0.5 - x,
        y: (svg?.clientHeight ?? 0) * 0.5 - y,
      };
      cutoutGroup.style.transformOrigin = measuredOrigin;
      solidGroup.style.transformOrigin = measuredOrigin;
    };

    updateOrigin();
    const resizeObserver = svg ? new ResizeObserver(updateOrigin) : null;
    if (svg) resizeObserver?.observe(svg);
    void document.fonts.ready.then(updateOrigin);

    return () => {
      cancelled = true;
      resizeObserver?.disconnect();
    };
  }, [activeOrigin, activePassageX, activePassageY, focusIndex, text]);

  const applyProgress = React.useCallback(
    (value: number) => {
      const cutoutGroup = cutoutGroupRef.current;
      const solidGroup = solidGroupRef.current;
      const solidText = solidTextRef.current;
      const curtain = curtainRef.current;
      const image = imageRef.current;
      if (!cutoutGroup || !solidGroup || !solidText || !curtain || !image) return;
      // Beat 1 — the complete word arrives as ordinary solid type.
      const entry = easeInOut(clamp01(value / 0.12));
      // Beat 2 — after a short hold, the solid word becomes a set of exact
      // transparent glyph cutouts. The opaque field around it never fades.
      const cutout = easeInOut(clamp01((value - 0.16) / 0.08));
      // Beat 3 — the cutout letters advance. The origin is placed inside the
      // inked shape of the selected glyph, not inside its counter.
      const flight = clamp01((value - 0.22) / 0.78);
      const targetScale = Math.max(1, activeMaxScale);
      const scale = 1 + (targetScale - 1) * Math.pow(flight, 2.15);
      const cameraTrack = easeInOut(clamp01(flight / 0.6));
      const passageShift = passageShiftRef.current;
      const transform = `translate3d(${(passageShift.x * cameraTrack).toFixed(3)}px, ${(passageShift.y * cameraTrack).toFixed(3)}px, 0) translateY(${((1 - entry) * 14).toFixed(3)}%) scale(${scale.toFixed(4)})`;
      const destinationScale = 1 + (Math.max(1, activeImageMaxScale) - 1) * Math.pow(flight, 1.15);
      cutoutGroup.style.transform = transform;
      solidGroup.style.transform = transform;
      cutoutGroup.style.opacity = cutout.toFixed(3);
      solidText.style.opacity = (entry * (1 - cutout)).toFixed(3);
      // Once the camera has crossed the transparent stroke, release the dark
      // field in one discrete handoff. It never fades or grows as a new shape.
      curtain.style.visibility = value >= 0.7 ? "hidden" : "visible";
      image.style.clipPath = "none";
      image.style.opacity = cutout > 0.001 ? "1" : "0";
      image.style.transform = `scale(${destinationScale.toFixed(4)})`;
      if (rootRef.current) {
        rootRef.current.dataset.phase = value < 0.12
          ? "entry"
          : value < 0.16
            ? "solid-hold"
            : value < 0.24
              ? "glyph-cutout"
              : value < 0.7
                ? "glyph-flight"
                : "image-arrival";
      }
    },
    [activeImageMaxScale, activeMaxScale],
  );

  useMotionValueEvent(progress, "change", (value) => {
    if (!reducedMotion) applyProgress(value);
  });

  React.useEffect(() => {
    if (!reducedMotion) applyProgress(progress.get());
  }, [applyProgress, progress, reducedMotion]);

  if (reducedMotion) {
    return (
      <section ref={rootRef} aria-label={label} data-knockout-text data-experience-viewport={viewport} data-static className={cn("relative grid min-h-svh place-items-center overflow-hidden px-4 sm:px-8", className)} style={{ backgroundColor: curtainColor }} {...props}>
        {overlay}
        <Tag
          className={cn("relative", textClassName)}
          style={{
            backgroundImage: `url("${activeSrc}")`,
            backgroundPosition: "center",
            backgroundSize: "cover",
            WebkitBackgroundClip: "text",
            backgroundClip: "text",
            color: "transparent",
          }}
        >
          {text}
        </Tag>
      </section>
    );
  }

  return (
    <section
      ref={rootRef}
      aria-label={label}
      data-knockout-text
      data-experience-viewport={viewport}
      className={cn("relative overflow-x-clip", className)}
      style={{ minHeight: `${Math.max(1.5, scrollScreens) * 100}svh`, backgroundColor: curtainColor }}
      {...props}
    >
      <Tag className="sr-only">{text}</Tag>
      <div className={cn("sticky top-0 h-svh overflow-hidden", stageClassName)}>
        {/* Fixed destination; the opaque curtain reveals it only inside the letters. */}
        <div
          ref={imageRef}
          aria-hidden
          data-knockout-image
          className="absolute inset-0 opacity-0 will-change-transform"
          style={{ backgroundImage: `url("${activeSrc}")`, backgroundSize: "cover", backgroundPosition: "center", transformOrigin: "center" }}
        />
        <svg aria-hidden className="absolute inset-0 size-full">
          <defs>
            <mask id={maskId} maskUnits="userSpaceOnUse" x="0" y="0" width="100%" height="100%">
              <rect width="100%" height="100%" fill="white" />
              <g
                ref={cutoutGroupRef}
                data-knockout-cutout
                className="will-change-transform"
                style={{ opacity: 0, transformBox: "view-box", transformOrigin: activeOrigin }}
              >
                {Array.from(text).map((character, index) => (
                  <text
                    key={`${character}-${index}`}
                    ref={(node) => { cutoutGlyphRefs.current[index] = node; }}
                    x="50%"
                    y="50%"
                    textAnchor="start"
                    dominantBaseline="central"
                    fill="black"
                    className={textClassName}
                  >
                    {character}
                  </text>
                ))}
              </g>
            </mask>
          </defs>
          {/* The dark field stays fully opaque; only the glyph shapes perforate it. */}
          <rect ref={curtainRef} width="100%" height="100%" fill={curtainColor} mask={`url(#${maskId})`} />
          {/* Stable, untransformed geometry source for responsive passage measurement. */}
          <text
            ref={measureTextRef}
            x="50%"
            y="50%"
            textAnchor="middle"
            dominantBaseline="central"
            className={textClassName}
            visibility="hidden"
          >
            {text}
          </text>
          {/* Entry type on the initial dark stage. */}
          <g ref={solidGroupRef} className="will-change-transform" style={{ transformBox: "view-box", transformOrigin: activeOrigin }}>
            <text
              ref={solidTextRef}
              data-knockout-solid
              x="50%"
              y="50%"
              textAnchor="middle"
              dominantBaseline="central"
              fill="currentColor"
              className={textClassName}
              style={{ opacity: 0 }}
            >
              {text}
            </text>
          </g>
        </svg>
        {overlay}
      </div>
    </section>
  );
}

"use client";

import * as React from "react";

export const EXPERIENCE_BREAKPOINTS = {
  tablet: 640,
  desktop: 1025,
} as const;

export type ExperienceViewport = "mobile" | "tablet" | "desktop";

export type ExperienceResponsiveValue<T> = T | {
  /** Mobile-first value, also used during SSR/hydration. */
  mobile: T;
  /** iPad/tablet value. Falls back to `mobile` when omitted. */
  tablet?: T;
  /** Wide-screen value. Falls back to `tablet`, then `mobile`. */
  desktop?: T;
};

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

/**
 * Shared mobile-first viewport contract for every experience primitive.
 *
 * Mobile: < 640px · tablet/iPad: 640–1024px · desktop: >= 1025px.
 * Pointer capability remains a separate signal because an iPad can gain a
 * trackpad without changing its layout profile.
 */
export function useExperienceViewport(): ExperienceViewport {
  const tablet = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.tablet}px)`);
  const desktop = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.desktop}px)`);
  if (desktop) return "desktop";
  if (tablet) return "tablet";
  return "mobile";
}

export function resolveExperienceValue<T>(
  value: ExperienceResponsiveValue<T>,
  viewport: ExperienceViewport,
): T {
  if (typeof value !== "object" || value === null || !("mobile" in value)) return value;
  if (viewport === "desktop") return value.desktop ?? value.tablet ?? value.mobile;
  if (viewport === "tablet") return value.tablet ?? value.mobile;
  return value.mobile;
}

/** Conservative raster/WebGL supersampling budget for each layout profile. */
export function getExperienceDprCap(width: number) {
  if (width < EXPERIENCE_BREAKPOINTS.tablet) return 1;
  if (width < EXPERIENCE_BREAKPOINTS.desktop) return 1.25;
  return 1.6;
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}

# Knockout Text

## Purpose

A pinned type-traversal sequence with no artificial aperture: the headline first enters as fully solid type, then those exact glyph shapes become transparent cutouts onto the destination. A selected central glyph advances until the camera passes through an inked part of its transparent form, not through its counter. The surrounding dark field never fades or becomes transparent, and no circle, ellipse, or independent reveal shape is introduced. The copy remains real text for accessibility and SEO.

## Install and use

```tsx
import { KnockoutText } from "@/components/experience/knockout-text";

<KnockoutText
  label="From dark, through the letters, into the image"
  as="h1"
  text="PORTAL"
  src="/media/hero-fill.webp"
  mobileSrc="/media/hero-fill-mobile.webp"
  scrollScreens={3.5}
  maxScale={210}
  mobileMaxScale={200}
  tabletMaxScale={210}
  imageMaxScale={1.5}
  mobileImageMaxScale={1.55}
  tabletImageMaxScale={1.52}
  focusIndex={2}
  passageX={0.15}
  passageY={0.5}
  textClassName="text-[clamp(4rem,17cqw,19rem)] font-bold leading-none tracking-tight text-white"
  overlay={<Chrome />}
/>
```

The stages are fixed fractions of the pinned travel (solid entry → short hold → transparent glyph cutouts → glyph flight → image arrival) and replay exactly in reverse. The image begins to show only inside the actual letterforms after the word is fully visible. During flight, the selected transparent stroke is tracked toward the viewport center while the destination performs a continuous push-in, so the passage reads as forward camera travel rather than lateral mask drift. The dark field never fades and no growing circle is introduced; after the camera has crossed the selected transparent stroke, the field is removed in one discrete handoff to the full image. `maxScale` controls the advancing glyphs; `imageMaxScale` controls the destination push-in, with mobile and tablet overrides for both. `focusIndex` selects the glyph, while `passageX`/`passageY` place the camera inside an inked part of its measured box; do not place this point in the glyph's counter. The component recalculates the point after resize and font loading, with responsive passage overrides available when needed. Explicit `origin` values remain available when no `focusIndex` is supplied. Reduced motion renders the real word filled with the destination image and removes the pin.

## Gates

- Use heavy, tight type: its strokes must stay legible after they become transparent and while the letterforms advance.
- Choose a visually central glyph with a broad stroke (`T`, `H`, `E`, `R`, `A`) and pass through that stroke, not through an enclosed counter.
- The measured `passageX`/`passageY` point must land inside the glyph's inked shape. At the endpoint, that transparent stroke must exceed the viewport.
- Keep the tracked passage point centered during the crossing and verify that the destination keeps scaling; the mask must not read as a horizontal pan.
- Keep the word solid until its entry is complete; only then transition its exact glyph shapes into image cutouts.
- Do not add radial/circular reveals and do not fade the surrounding dark field. Only the letterforms become transparent.
- The opaque field around the letters needs sufficient contrast; choose `curtainColor` accordingly.
- Verify the takeover endpoint: at progress 1 the full image must be composed art direction, not an accidental crop; check 390px as well as desktop.
- The image is decorative; any information it carries must also exist as real content nearby. Test 200% zoom and `clamp()` the font size so the word never overflows mid-zoom.
